select *
from batch.retry_schedule
where 1 = 1

    and tenant_id = #{tenantId}


    and retry_status = #{retryStatus}


    and next_retry_at <= #{dueBefore}

order by next_retry_at asc, id asc

    limit #{batchSize}

mapper.update:
update batch.retry_schedule
set retry_status = #{runningStatus},
    updated_at = current_timestamp
where id = #{id}
  and retry_status = #{fromStatus}
